dels-table1.csv. Be aware that this will take many hours. tbl <- read.csv("jepfittedmodels-table1.csv") tab <- tbl[,3:ncol(tbl)] rownames(tab) <- tbl[,2] tab <- tab[1:5, c(1,2,3,5)] colnames(tab) <- c("in sample MSE", "in sample R^2", "out of sample MSE", "out of sample R^2") library(kableExtra) kable_styling(kable(tab, caption="Performance of different algorithms in predicting housing values", format="html", digits=3), bootstrap_options = c("striped", "hover", "condensed", "responsive"), full_width=TRUE) Performance of different algorithms in predicting housing values in sample MSE in sample R\^2 out of sample MSE out of sample R\^2 OLS 0.589 0.473 0.674 0.417 Tree 0.675 0.396 0.758 0.345 Lasso 0.603 0.460 0.656 0.433 Forest 0.166 0.851 0.632 0.454 Ensemble 0.216 0.807 0.625 0.460 library(ggplot2) load(file="jeperrorfig.RData") print(fig) load(file="jeperrorfig.RData") print(fig2) Predicting pipeline revenues ¶ Data on US natural gas pipelines Combination of FERC Form 2, EIA Form 176, and other sources, compiled by me 1996-2016, 236 pipeline companies, 1219 company-year observations Predict: $y =$ profits from transmission of natural gas Covariates: year, capital, discovered gas reserves, well head gas price, city gate gas price, heating degree days, state(s) that each pipeline operates in load("pipelines.Rdata") # data has problems before 1996 due to format change data <- subset(data,report_yr>=1996) # replace NA state weights with 0's data[,59:107][is.na(data[,59:107])] <- 0 # spaces in variable names will create problems later names(data) <- gsub(" ",".",names(data)) summary(data[,c("transProfit","transPlant_bal_beg_yr","cityPrice","wellPrice")]) ## transProfit transPlant_bal_beg_yr cityPrice ## Min. : -31622547 Min. :0.000e+00 Min. : 0.4068 ## 1st Qu.: 2586031 1st Qu.:2.404e+07 1st Qu.: 3.8666 ## Median : 23733170 Median :1.957e+08 Median : 5.1297 ## Mean : 93517513 Mean :7.772e+08 Mean : 5.3469 ## 3rd Qu.: 129629013 3rd Qu.:1.016e+09 3rd Qu.: 6.5600 ## Max. :1165050214 Max. :1.439e+10 Max. :12.4646 ## NA's :2817 NA's :2692 NA's :1340 ## wellPrice ## Min. :0.0008 ## 1st Qu.:2.1230 ## Median :3.4370 ## Mean :3.7856 ## 3rd Qu.:5.1795 ## Max. :9.6500 ## NA's :2637 library(GGally) ggpairs(data[,c("transProfit","transPlant_bal_beg_yr","cityPrice","wellPrice")], lower=list(continuous="smooth")) + theme_minimal() Predicting pipeline revenues : methods ¶ OLS : 67 covariates (year dummies and state(s) create a lot) Lasso Random forests Randomly choose 75% of sample to fit the models, then look at prediction accuracy in remaining 25% We are focusing on Lasso and random forests because these are the two methods that econometricians have worked on the most. Other methods such as neural nets and support vector machines are also worth exploring. For now, you can think of Lasso and random forests these as black boxes that generate predictions from data. We will go into more detail soon. ## Create X matrix for OLS and random forests xnames <-c("transPlant_bal_beg_yr", "reserve", "wellPrice", "cityPrice", "plantArea", "heatDegDays", names(data)[59:107] ) yname <- "transProfit" fmla <- paste(yname,"~",paste(xnames,collapse=" + "),"+ as.factor(report_yr)") ols <- lm(fmla,data=data,x=TRUE,y=TRUE) X <- ols$x[,!(colnames(ols$x) %in% c("(Intercept)")) & !is.na(ols$coefficients)] y <- ols$y train <- runif(nrow(X))<0.75 # OLS prediction on training set y.t <- y[train] X.t <- X[train,] ols <- lm(y.t ~ X.t) y.hat.ols <- ols$coefficients[1] + X %*% ols$coefficients[2:(length(ols$coef))] df <- data.frame(y=y, y.hat=y.hat.ols, train=train, method="ols") ## Lasso library(glmnet) # Create larger X matrix for lasso fmla.l <- paste(yname,"~ (", paste(xnames,collapse=" + "),")*(report_yr + transPlant_bal_beg_yr + reserve + wellPrice + cityPrice + plantArea + heatDegDays) + ", paste(sprintf("I(%s^2)",xnames[1:6],collapse=" + ")) ) reg <- lm(fmla.l, data=data, x=TRUE,y=TRUE) Xl <- reg$x[,!(colnames(reg$x) %in% c("(Intercept)")) & !is.na(reg$coefficients)] lasso <- cv.glmnet(Xl[train,],y[train],alpha=1,parallel=FALSE, standardize=TRUE, intercept=TRUE, nfolds = 50) y.hat.lasso <- predict(lasso, Xl, s=lasso$lambda.min, type="response") df <- rbind(df, data.frame(y=y, y.hat=as.vector(y.hat.lasso), train=train, method="lasso")) ## Random forest library(grf) rf <- regression_forest(X[train,],y[train],tune.parameters = TRUE) y.hat.rf <- predict(rf, X)$predictions df <- rbind(df, data.frame(y=y, y.hat=y.hat.rf, train=train, method="random forest")) # Neural network library(RSNNS) n <- nrow(X[train,]) p <- ncol(X) rn <- floor(n^(1/(2*(1+1/(1+p))))/2) xn <- normalizeData(X) yn <- normalizeData(y) nn <- mlp(x=xn[train,], y=yn[train], linOut=TRUE, size=rn) yn.hat.nn <- predict(nn, xn) y.hat.nn <- denormalizeData(yn.hat.nn, getNormParameters(yn)) df <- rbind(df, data.frame(y=y, y.hat=y.hat.nn, train=train, method="neural network")) ggplot(data=df,aes(x=y,y=y.hat,colour=method,shape=train)) + geom_point(alpha=0.5) + geom_line(aes(y=y)) + theme_minimal() df$trainf <- factor(df$train, levels=c("TRUE", "FALSE")) df$error <- df$y - df$y.hat ggplot(data=df,aes(x=error,colour=method)) + geom_density() + theme_minimal() + xlim(quantile(df$error,c(0.01,0.99))) + facet_grid(trainf ~ .,labeller=label_both) library(kableExtra) fn <- function(df) with(df,c(mean((y.hat - y)^2)/var(y), mean(abs(y.hat - y))/mean(abs(y-mean(y))))) tab1 <-unlist(by(subset(df,train), df$method[train], FUN=fn)) tab1 <- (matrix(tab1,nrow=2)) rownames(tab1) <- c("relative MSE","relative MAE") colnames(tab1) <- c("OLS","Lasso","Random forest","Neural Network") tab2 <- unlist(by(subset(df,!train), df$method[!train], FUN=fn)) tab2 <- (matrix(tab2,nrow=2)) rownames(tab2) <- c("relative MSE","relative MAE") colnames(tab2) <- c("OLS","Lasso","Random forest","Neural Network") kable_styling(kable(tab1, caption="Training sample", format="html", digits=3), bootstrap_options = c("striped", "hover", "condensed", "responsive"), full_width=F) Training sample OLS Lasso Random forest Neural Network relative MSE 0.110 0.031 0.063 0.012 relative MAE 0.265 0.137 0.179 0.111 kable_styling(kable(tab2, caption="Hold-out sample", format="html", digits=3), bootstrap_options = c("striped", "hover", "condensed", "responsive"), full_width=F) Hold-out sample OLS Lasso Random forest Neural Network relative MSE 0.125 0.064 0.093 0.092 relative MAE 0.288 0.199 0.232 0.278 In this table, relative MSE is the mean squared error relative to the variance of $y$, that is 	ext{relative MSE} =  rac{\En[(y_i - \hat{y}_i)^2]} {\En[ (y_i -  ar{y})^2]}. It is equal to $1-R^2$. Similarly, relative MAE is 	ext{relative MAE} =  rac{\En[|y_i - \hat{y}_i|]} {\En[|y_i -  ar{y}|]}. $\En$ denotes the empirical expectation, $\En[y_i] =  rac{1}{n}\sum_{i=1}^n y_i$. Lasso ¶ Lasso solves a penalized (regularized) regression problem \hat{ eta} = \argmin_ eta \En [ (y_i - x_i' eta)^2 ] +  rac{\lambda}{n} 
orm{ \hat{\Psi}  eta}_1 Penalty parameter $\lambda$ Diagonal matrix $\hat{\Psi} = diag(\hat{\psi})$ Dimension of $x_i$ is $p$ and implicitly depends on $n$ can have $p >> n$ We are following the notation used in Chernozhukov, Hansen, and Spindler ( 2016 ). Note that this vignette has been updated since it was published in the R Journal. To obtain the most recent version, install the hdm package in R, load it, and then open the vignette. install.packages("hdm") library(hdm) vignette("hdm_introduction") The choice of penalty (or regularization) parameter, $\lambda$, is important. When $\lambda = 0$, Lasso is the same as OLS. As $\lambda$ increases, the Lasso estimates will shrink toward 0. For large enough $\lambda$, some components of $\hat{ eta}$ become exactly 0. As $\lambda$ increases more, more and more components of $\hat{ eta}$ will be exactly $0$. For some intuition about why Lasso results in some coefficients being zero, note that \hat{ eta}^{lasso} = \argmin_ eta \En [ (y_i - x_i' eta)^2 ] +  rac{\lambda}{n} 
orm{ eta}_1 is equivalent to \hat{ eta}^{lasso} = \argmin_ eta \En [ (y_i - x_i' eta)^2 ] 	ext{ s.t. } 
orm{ eta}_1 \leq s for some $s$. In this problem, the boundary of the constraint set will be a diamond. The level sets of the objective will be elipses. Generically, the solution will lie on one of the corners of the $
orm{ eta}_1 = 1$ set. See Friedman, Hastie, and Tibshirani ( 2009 ) or James et al. ( 2013 ) for more details. Most machine learning methods involve some form of regularization with an associated regularization parameter. In choosing the regularization parameter, we face a bias-variance tradeoff. As $\lambda$ increases, variance decreases, but bias increases. Machine learning algorithms typically choose regularization parameters through cross-validation. Although cross-validation leads to good predictive performance, the statistical properties are not always known. Chernozhukov, Hansen, and Spindler ( 2016 ) say, “In high dimensional settings cross-validation is very popular; but it lacks a theoretical justification for use in the present context.” However, there has been some recent progress on convergence rates for Lasso with cross-validation, see Chetverikov, Liao, and Chernozhukov ( 2016 ). The diagonal matrix $\hat{\Psi}$ is used to make the estimator invariant to scaling of $x_i$, and to allow for heteroskedasticity. If reading about Lasso or using code from other authors, be careful some do not include $\hat{\Psi}$ and use $\lambda$ instead of $ rac{\lambda}{n}$. load("~/natural-gas-pipelines/dataAndCode/pipelines.Rdata") data <- subset(data,report_yr>=1996) library(glmnet) mod <- lm(transProfit ~ transPlant_bal_beg_yr + reserve + wellPrice + cityPrice + plantArea + heatDegDays, data=data, x=T, y=T) # standardize everything so that coefficients are similar scale when plotted mod$y <- (mod$y - mean(mod$y))/sd(mod$y) for(c in 2:ncol(mod$x)) { mod$x[,c] <- (mod$x[,c] - mean(mod$x[,c]))/sd(mod$x[,c]) } lassoPath <- glmnet(mod$x, mod$y, alpha=1) plot(lassoPath, xvar="lambda", label=TRUE) load("~/natural-gas-pipelines/dataAndCode/pipelines.Rdata") data <- subset(data,report_yr>=1996) library(glmnet) mod <- lm(transProfit ~ transPlant_bal_beg_yr + reserve + wellPrice + cityPrice + plantArea + heatDegDays, data=data, x=T, y=T) # standardize everything so that coefficients are similar scale when plotted mod$y <- (mod$y - mean(mod$y))/sd(mod$y) for(c in 2:ncol(mod$x)) { mod$x[,c] <- (mod$x[,c] - mean(mod$x[,c]))/sd(mod$x[,c]) } cv <- cv.glmnet(mod$x, mod$y, alpha=1) plot(cv) Statistical properties of Lasso ¶ Model : y_i = x_i' eta_0 + \epsilon_i $\Er[x_i \epsilon_i] = 0$ $ eta_0 \in \R^n$ $p$, $ eta_0$, $x_i$, and $s$ implicitly depend on $n$ $\log p = o(n^{1/3})$ $p$ may increase with $n$ and can have $p>n$ Sparsity $s$ Exact : $
orm{ eta_0}_0 = s = o(n)$ Approximate : $| eta_{0,j}| < Aj^{-a}$, $a > 1/2$, $s \propto n^{1/(2a)}$ $
orm{ eta}_0$ is the number of non-zero components of $ eta$. The approximate sparsity setting means if $| eta_{0,j}| < Aj^{-a}$, then, there exists a sparse approximation, say $ eta_{a}$, with $s$ nonzero elements, such that the approximation error, \En[(x_i'( eta_a -  eta_0))^2] = c_s^2 will vanish quickly if $s \propto n^{1/2a}$. Just how quickly will it vanish? An easy upper bound is  egin{align*} c_s^2 \leq & \En\left[\left( \sum_{j={s+1}}^p x_ij  eta_{0,j} ight)^2 ight] \ \leq & \En\left[ \left(\sum_{j={s+1}}^p x_ij A j^{-a} ight)^2 ight] \end{align*} To simplify the alegebra, let’s assume $\En[x_i x_i’] = I_p$, then  egin{align*} c_s^2 \leq & \sum_{j={s+1}}^p A^2 j^{-2a} \ & \leq \sum_{j={s+1}}^\infty A^2 j^{-2a} = A^2 s^{-2a} \zeta(2a) \ c_s^2 \lesssim s^{-2a} \end{align*} where $\zeta(2a) = \sum_{j=1}^\infty j^{-2a}$ is the Riemann Zeta function (all that matters here is that $\zeta(2a)$ is finite for $2a>1$). Then if $s \propto n^{(1+\delta)/2a}$, we would get $c_s \lesssim n^{-(1+\delta)/2}$. Importantly, $\sqrt{n} c_s = o(1)$, so in the sort of expansions that we would do to show that $\hat{	heta}$ is $\sqrt{n}$ asymptotically normal, the bias term would vanish. Rate of convergence ¶ With $\lambda = 2c \sqrt{n} \Phi^{-1}(1-\gamma/(2p))$ \sqrt{\En[(x_i'(\hat{ eta}^{lasso} -  eta_0))^2 ] } \lesssim_P \sqrt{ (s/n) \log (p) }, 
orm{\hat{ eta}^{lasso} -  eta_0}_2 \lesssim_P \sqrt{ (s/n) \log (p) }, and 
orm{\hat{ eta}^{lasso} -  eta_0}_1 \lesssim_P \sqrt{ (s^2/n) \log (p) } Constant $c>1$ Small $\gamma 	o 0$ with $n$, and $\log(1/\gamma) \lesssim \log(p)$ Rank like condition on $x_i$ near-oracle rate In the semiparametric estimation problems that we’re focused on, our object of interest is some finite dimensional parameter $	heta$ that depends on our data some high dimensional parameter, like $ eta_0$ in the Lasso. To analyze estimates of $\hat{	heta}(data, \hat{ eta})$, a key step will be to show that we can replace $\hat{ eta}$ with $ eta_0$. The rate of convergence of $\hat{ eta}$ will be important for making this possible. Thus, the main thing that we care about for the Lasso and other machine learning estimators will be their rates of converagence. The notation $A_n \lesssim_P B_n$ is read $A_n$ is bounded in probability by $B_n$ and means that for any $\epsilon>0$, there exists $M$, $N$ such that $\Pr(|A_n/B_n| > M) < \epsilon$ for all $n > N$. This is also often denoted by $A_n = O(B_n)$. These rate results are from Belloni et al. ( 2012 ). Since this setup allows $p>n$, $x$ cannot be assumed to have full rank. Instead, an assumption about the eigenvalues of $X’X$ restricted to the nonzero components of $ eta_0$, plays a similar. See Belloni et al. ( 2012 ) for details. This convergence rate is called the near-oracle rate, because it is nearly as good as what we get if an oracle told us which components of $ eta_0$ are nonzero. In that case OLS using just those $s$ components gives the fastest possible rate, which is \sqrt{\En[(x_i'(\hat{ eta}^{OLS} -  eta_0))^2]} \propto \sqrt{s/n}. Rate of convergence [rate-of-convergence-1] ¶ Using cross-validation to choose $\lambda$ known bounds are worse With Gaussian errors: $\sqrt{\En[(x_i’(\hat{ eta}^{lasso} -  eta_0))^2 ] } \lesssim_P \sqrt{ (s/n) \log (p) } \log(pn)^{7/8}$, Without Gaussian error $\sqrt{\En[(x_i’(\hat{ eta}^{lasso} -  eta_0))^2 ] } \lesssim_P \left(  rac{s \log(pn)^2}{n} ight)^{1/4}$ Chetverikov, Liao, and Chernozhukov ( 2016 ) These results are for an exactly sparse setting. Do they hold under approximate sparsity? Other statistical properties ¶ Inference on $ eta$: not the goal in our motivating examples Difficult, but some recent results See Lee et al. ( 2016 ), Taylor and Tibshirani ( 2017 ), Caner and Kock ( 2018 ) Model selection: not the goal in our motivating examples Under stronger conditions, Lasso correctly selects the nonzero components of $ eta_0$ See Belloni and Chernozhukov ( 2011 ) In the statistics literature on high dimensional and nonparametric estimation, you will come across the terms “adaptive” and “honest.” Adaptivity of an estimator refers to the situation where the rate of convergence depends on some unknown parameter. In the case of Lasso, the sparsity index of the true model, $s$, is an unknown parameter affecting the rate of convergence. Without knowing or estimating $s$, Lasso attains the above rate of convergence for a wide range of admissable $s$. Thus, Lasso is adaptive to the unknown sparsity index. “Honest” is a property of an inference method. A confidence region is honest if it has correct coverage for a large class of true models. For the Lasso, an honest confidence region would be valid for a wide range of sparsity, $s$. An honest, adaptive confidence region would be one that is valide for a wide range of $s$ and whose size shrinks as quickly as if $s$ were known. Achieving both adaptivity and honesty is impossible in the most general setting. For example, although an $\ell$ times differentiable function of a $p$ dimensional variable can be adaptively estimated at rate $n^{-\ell}{2\ell + p}$, Li ( 1989 ) showed that an honest confidence region can contract at most at rate $n^{-1/4}$ (not adaptive to $\ell$). However, an adaptive confidence region can be constructed if further restrictions are placed on the set of possible models, see Nickl and Geer ( 2013 ) for such a result for Lasso.. Post-Lasso ¶ Two steps : Estimate $\hat{ eta}^{lasso}$ ${\hat{ eta}}^{post} =$ OLS regression of $y$ on components of $x$ with nonzero $\hat{ eta}^{lasso}$ Same rates of convergence as Lasso Under some conditions post-Lasso has lower bias If Lasso selects correct model, post-Lasso converges at the oracle rate Post-Lasso removes some of the regularizaton bias of Lasso. The rate of convergence of post-Lasso is always as fast as Lasso, and under conditions that allow perfect model selection, post-Lasso converges slightly faster (by a factor $\log(p)$). See Belloni et al. ( 2012 ) for details. Random forests ¶ Regression trees ¶ $y_i \in R$ on $x_i \in \R^p$ Want to estimate $\Er[y | x]$ Locally constant estimate \hat{t}(x) = \sum_m^M c_m 1\{x \in R_m \} Rectangular regions $R_m$ determined by tree Simulated data ¶ n <- 1000 x <- runif(n) y <- runif(n) f <- function(x,z) { 1/3*(sin(5*x)*sqrt(z)*exp(-(z-0.5)^2)) } f0 <- f(x,y) z <- f0 + rnorm(n)*0.1 tree.df <- data.frame(x=x,y=y,z=z) # plot true function and data x.g <- seq(0,1,length.out=100) y.g <- seq(0,1,length.out=100) f0.g <- t(outer(x.g,y.g,f)) library(plotly) fig <- plot_ly( colors="YlOrBr") fig <- add_markers(fig,x=x,y=y,z=z, size=0.3, opacity=0.2) fig <- add_surface(fig, x=x.g, y=y.g, z=f0.g, opacity=1) fig Estimated tree ¶ # fit regression tree library(party) tree <- ctree(z ~ x + y, data=tree.df) # plot estimate x.g <- seq(0,1,length.out=100) y.g <- seq(0,1,length.out=100) df <- expand.grid(x.g,y.g) names(df) <- c("x","y") fhat.g <- matrix(predict(tree, newdata=df),nrow=length(x.g), byrow=TRUE) library(plotly) fig <- plot_ly(colors="YlOrBr") fig <- add_markers(fig,x=x,y=y,z=z, size=0.3, opacity=0.2) fig <- add_surface(fig, x=x.g, y=y.g, z=fhat.g, opacity=1) fig Estimated tree ¶ plot(tree) Tree algorithm ¶ For each region, solve \min_{j,s} \left[ \min_{c_1} \sum_{i: x_{i,j} \leq s, x_i \in R} (y_i - c_1)^2 + \min_{c_2} \sum_{i: x_{i,j} > s, x_i \in R} (y_i - c_2)^2 ight] Repeat with $R = {x:x_{i,j} \leq s^ } \cap R$ and $R = {x:x_{i,j} \leq s^ } \cap R$ Stop when $|R| =$ some chosen minimum size Prune tree \min_{tree \subset T} \sum (\hat{f}(x)-y)^2 + \alpha|	ext{terminal nodes in tree}| There are many variations on this tree building algorithm. They all share some rule to decide on which variable and where to split. They all have some kind of stopping rule, but not necessarily the same one. For example, some algorithms stop splitting into new branches when the improvement in $R^2$ becomes small. These trees don’t need subsequent pruning, but also may fail to find later splits that might be important. As with lasso, regression trees involve some regularization. In the above description, both the minimum leaf size and $\alpha$ in the pruning step serve as regularization parameters. A potential advantage of regression trees is that their output might be interpretable, especially if there are not many branches. Some disadvantages are that they often are not very good predictors, and small perturbations in data can lead to seemingly large changes in the tree. Random forests ¶ Average randomized regression trees Trees randomized by Bootstrap or subsampling Randomize branches: \min_{j \in S,s} \left[ \min_{c_1} \sum_{i: x_{i,j} \leq s, x_i \in R} (y_i - c_1)^2 + \min_{c_2} \sum_{i: x_{i,j} > s, x_i \in R} (y_i - c_2)^2 ight] where $S$ is random subset of ${1, …, p}$ Variance reduction Rate of convergence: regression tree ¶ $x \in [0,1]^p$, $\Er[y|x]$ Lipschitz in $x$ Crude calculation for single tree, let denote $R_i$ node that contains $x_i$  egin{align*} \Er(\hat{t}(x_i) - \Er[y|x_i])^2 = & \overbrace{\Er(\hat{t}(x_i) - \Er[y|x\in R_i])^2}^{variance} + \overbrace{(\Er[y|x \in R_i] - \Er[y|x])^2}^{bias^2} \ = & O_p(1/m) + O\left(L^2 \left( rac{m}{n}ight)^{2/p}ight) \end{align*} optimal $m = O(n^{2/(2+p)})$ gives \Er[(\hat{t}(x_i) - \Er[y|x_i])^2] = O_p(n^{ rac{-2}{2+p}}) By a crude calculation, I mean lets treat the tree as fixed. The the variance term is simply from estimating a conditional mean. This analysis could be made more rigorous by assuming the tree was estimated by sample splitting — use half the data to construct the tree and the remaining half to estimate the mean of $y$ in each node. Athey and Wager, and others, refer to such trees as “honest.” I suppose that this is because sample splitting facilitates honest inference afterward. The order of the bias term comes from considering the width of the pieces of a $p$ dimensional cube split evenly into $n/m$ pieces. Remember that for our motivating semiparametric problems, we need $\sqrt{n} \Er[(\hat{t}(x_i) - \Er[y|x_i])^2]$ to vanish. The above rate convergence is too slow for $p>2$. The calculation of the above was admittedly crude, and may not be exact. However, Stone ( 1982 ) showed that if $\Er[y|x]$ is $\ell$ times differentiable, the fastest possible rate of convergence for any estimator is $n^{ rac{-\ell}{2\ell + p}}$. To have any hope of a fast enough rate, we need to assume the function we’re estimating is very smooth (high $\ell$), or place some other restriction on the class of functions we allow (like sparsity for the Lasso). Lipschitz continuity is slightly weaker than once differentiable on a compact set, so it should come as no surprise that the rate of convergence would be slow. Rate of convergence: random forest ¶ Result from Biau ( 2012 ) Assume $\Er[y|x]=\Er[y|x_{(s)}]$, $x_{(s)}$ subset of $s$ variables, then \Er[(\hat{r}(x_i) - \Er[y|x_i])^2] = O_p\left( rac{1}{m\log(n/m)^{s/2p}}ight) + O_p\left(\left( rac{m}{n}ight)^{ rac{0.75}{s\log 2}} ight) or with optimal $m$ \Er[(\hat{t}(x_i) - \Er[y|x_i])^2] = O_p(n^{ rac{-0.75}{s\log 2+0.75}}) This result from Biau ( 2012 ) assumes the forest is estimated with sample splitting. This avoids the difficult to analyze correlation between the nodes and $y$. Wager and Walther ( 2015 ) analyze what happens when the same data is used to construct the tree and average in each node. They get a slightly higher upper bound for the variance of $ rac{\log(p)\log(n)}{m}$. Wager and Walther ( 2015 ) also allow $p$ to increase with $n$, whereas the previous analysis treated $p$ as fixed. These convergence rate results for random forests are not fast enough for our purpose. Does this mean that random forests should not be used in semiparametric estimation? Not necessarily. We’re asking too much of random forests. There is no estimator for an arbitrary Lipschitz function that can have fast enough a rate of convergence. A restriction on the set of possible functions is needed to reduce the approximation bias. With Lasso, the assumption of (approximate) sparsity played that role. Chernozhukov et al. ( 2018 ) advise that random forests could be a good choice for semiparametric estimation when the function of interest is “well-approximated by a random forest.” Unfortunately, there does not appear to be a clean mathematical way to describe the class of functions well-approximated by a forest. Other statistical properties ¶ Pointwise asymptotic normality : Wager and Athey ( 2018 ) Simulation study ¶ Partially linear model DGP : $x_i \in \R^p$ with $x_{ij} \sim U(0,1)$ $d_i = m(x_i) + v_i$ $y_i = d_i	heta + f(x_i) + \epsilon_i$ $m()$, $f()$ either linear or step functions Estimate by OLS, Lasso, and random forest Lasso & random forest use orthogonal moments \En[(d_i - \hat{m}(x_i))(y_i - \hat{\mu}(x_i) - 	heta (d_i - \hat{m}(x_i)))] = 0 The point of this simulation is to see whether the slower convergence rate of random forests matters for the semiparametric problems we have in mind. Our theory results suggest that estimates of $	heta$ using random forests with $p>2$ will be asymptotically biased. Specifically, the term d_n = \En[(m(x_i) - \hat{m}(x_i))(\mu(x_i) - \hat{\mu}(x_i))] will be $O_p(n^{ rac{-2}{2+p}})$, so $\sqrt{n} d_n = O_p(n^{ rac{p-2}{2(2+p)}})$. However, this calculation is only an upper bound on $d_n$. For a given DGP, $d_n$ might be smaller. In this simulation exercise, when $m()$ and $f()$ are linear, they are not easy to approximate by a regression tree, so I expect the random forest estimator to behave relatively poorly. OLS and Lasso on the other hand will do very well, and are included mainly as benchmarks. When $m()$ and $f()$ are step functions (specifically, $f(x) = m(x) = \sum_{j=1}^p 1(x_{j}>1/2)$), I thought they would be well approximated by a regression tree (and random forest). For OLS and Lasso, $x$ is still only included linearly in the estimation, so those estimators will do poorly in the step function DGP. Throughout the simulation $p$ is much less than $n$, so Lasso and OLS will generally give very similar results. rm(list=ls()) p <- 4 # number of x's mu.linear <- function(x) x%*%rep(1,p) m.linear <- function(x) x%*%rep(2,p) mu.step <- function(x) (x>0.5)%*%rep(1,p) m.step <- function(x) (x>0.5)%*%rep(2,p) theta <- 1 simulate <- function(n,p,mu,m) { theta <- 1 x <- matrix(runif(n*p), ncol=p) d <- m(x) + rnorm(n) y <- theta*d + mu(x) + rnorm(n) data.frame(y=y,d=d,x=x) } library(grf) library(hdm) df <- simulate(100,p,mu.linear,m.linear) mrfparams <- NULL murfparams <- NULL n.save <- NULL partial.linear.rf <- function(df) { x.names <- names(df)[grep("x.",names(df))] if (is.null(mrfparams) || n.save!=nrow(df)) { # to save time, we only tune once per cluster worker and data set # size cat("tuning") m.rf <- regression_forest(df[,x.names], df$d, num.trees=1000, tune.parameters=TRUE) mrfparams <<- m.rf$tunable.params mu.rf <- regression_forest(df[,x.names], df$y, num.trees=1000, tune.parameters=TRUE) n.save <<- nrow(df) murfparams <<- mu.rf$tunable.params } else { cat("not tuning") m.rf <- regression_forest(df[,x.names], df$d, num.trees=200, tune.parameters=FALSE, min.node.size = as.numeric(mrfparams["min.node.size"]), alpha = as.numeric(mrfparams["alpha"]), imbalance.penalty=as.numeric(mrfparams["imbalance.penalty"]), sample.fraction = as.numeric(mrfparams["sample.fraction"]), mtry=as.numeric(mrfparams["mtry"])) mu.rf <- regression_forest(df[,x.names], df$y,