l"), keep="pkh", omit.table.layout="n",omit.stat = c("rsq","adj.rsq","ser")) ITT estimates Dependent variable: Doctor Midwife Traditional (1) (2) (3) pkh_kec_ever 0.043 *** 0.094 *** -0.090 *** (0.012) (0.017) (0.016) Observations 6,629 6,629 6,629 Delivery attendant usage [delivery-attendant-usage-1] ¶ stargazer(iv, type="html", title="IV effect of program participation", dep.var.labels = c("Doctor","Midwife","Traditional"), keep="pkh", omit.table.layout="n",omit.stat = c("rsq","adj.rsq","ser")) IV effect of program participation Dependent variable: Doctor Midwife Traditional (1) (2) (3) pkh_ever(fit) 0.091 *** 0.198 *** -0.189 *** (0.025) (0.036) (0.035) Observations 6,629 6,629 6,629 Health outcomes ¶ library(lfe) lhs <- "pkh_kec_ever + doctor_birth_base + as.factor(edu) + as.factor(agecat) + log_xp_percap + hh_land + hh_home | dist | 0 | Location_ID" itt <- list(felm(as.formula(paste("death_ch ~",lhs)),data=pw), felm(as.formula(paste("bw ~",lhs)),data=pw), felm(as.formula(paste("bw_low ~",lhs)),data=pw)) lhs <- "doctor_birth_base + as.factor(edu) + as.factor(agecat) + log_xp_percap + hh_land + hh_home | dist | (pkh_ever ~ pkh_kec_ever) | Location_ID" iv <- list(felm(as.formula(paste("death_ch ~",lhs)),data=pw), felm(as.formula(paste("bw ~",lhs)),data=pw), felm(as.formula(paste("bw_low ~",lhs)),data=pw)) library(stargazer) stargazer(itt, type="html", title="ITT estimates", dep.var.labels = c("Infant mortality","Birthweight","Low birthweight"), keep="pkh", omit.table.layout="n",omit.stat = c("rsq","adj.rsq","ser")) ITT estimates Dependent variable: Infant mortality Birthweight Low birthweight (1) (2) (3) pkh_kec_ever 0.005 -5.559 0.017 (0.004) (23.805) (0.012) Observations 8,303 4,988 4,988 Health outcomes [health-outcomes-1] ¶ stargazer(iv, type="html", title="IV effect of program participation", dep.var.labels = c("Infant mortality","Birthweight","Lowbirthweigt"), keep="pkh", omit.table.layout="n",omit.stat = c("rsq","adj.rsq","ser")) IV effect of program partic