apse=" + ")), data=subset(df,main)) gc <- grep("G", names(greg$coefficients)) gate[i,] <- greg$coefficients[gc] if (is.null(clusterid)) gate.se[i,] <- sqrt(diag(vcovHC(greg))[gc]) else gate.se[i,] <- sqrt(diag(vcovCL(greg, clusterid[main]))[gc]) Lambda[i,2] <- sum(gate[i,]^2)/n.group } out <- list( gate=gate, gate.se=gate.se, blp=blp, blp.se=blp.se, Lambda=Lambda, baseline=baseline, cate=cate) } genericML.summary <- function(gml) { blp <- apply(gml$blp, 2, function(x) median(x, na.rm=TRUE)) blp.se <- apply(gml$blp.se, 2, function(x) median(x, na.rm=TRUE)) gate <- apply(gml$gate, 2, function(x) median(x, na.rm=TRUE)) gate.se <- apply(gml$gate.se, 2, function(x) median(x, na.rm=TRUE)) Lambda <- apply(gml$Lambda, 2, function(x) median(x, na.rm=TRUE)) return(list(blp=blp, blp.se=blp.se, gate=gate, gate.se=gate.se, Lambda=Lambda)) } library(glmnet) # create x matrix fmla.l <- bw ~ pkh_kec_ever + as.factor(edu)*as.factor(agecat) + log_xp_percap + hh_land + hh_home + as.factor(dist) + hh_phone + hh_rf_tile + hh_rf_shingle + hh_rf_fiber + hh_wall_plaster + hh_wall_brick + hh_wall_wood + hh_wall_fiber + hh_fl_tile + hh_fl_plaster + hh_fl_wood + hh_fl_dirt + hh_water_pam + hh_water_mechwell + hh_water_well + hh_water_spring + hh_water_river + hh_waterhome + hh_toilet_own + hh_toilet_pub + hh_toilet_none + hh_waste_tank + hh_waste_hole + hh_waste_river + hh_waste_field + hh_kitchen + hh_cook_wood + hh_cook_kerosene + hh_cook_gas + tv + fridge + motorbike + car + goat + cow + horse m <- lm(fmla.l, data=pw, x=TRUE, y=TRUE) treat <- m$x[,2] Xl <- m$x[,3:ncol(m$x)] scale <- sd(m$y) center <- mean(m$y) yl <- (m$y-center)/scale lid <- as.factor(pw[as.numeric(rownames(m$x)),]$Location_ID) gml.lasso <- genericML(Xl,m$y, treat, function(x,y) cv.glmnet(x,(y-center)/scale,alpha=1,parallel=FALSE, intercept=TRUE, nfolds=20), function(model, x) { predict(model, x, s=model$lambda.min, type="response")*scale + center }, n.split=11,n.group=5, clusterid=lid) library(grf) gml.rf <- genericML(Xl,m$y, treat, function(x,y) regression_forest(x, (y-center)/scale, tune.parameters=TRUE), function(model, x) { predict(model,x)$predictions*scale + center}, n.split=11,n.group=5, clusterid=lid) library(RSNNS) gml.nn <- genericML(Xl,m$y, treat, function(x,y) mlp(x,(y-center)/scale,linOut=TRUE, size=c(10,10), learnFunc="SCG"), function(model, x) { predict(model,x)*scale + center}, n.split=11,n.group=5, clusterid=lid) library(GGally) df <- data.frame(Lasso=apply(gml.lasso$cate,1,median), Forest=apply(gml.rf$cate,1,median), Neural=apply(gml.nn$cate,1,median)) ggpairs(df, lower=list(continuous="smooth")) + theme_minimal() Best linear projection of CATE ¶ Randomly partition sample into auxillary and main samples Use any method on auxillary sample to estimate S(x) = \widehat{\Er[y(1) - y(0) | x]} and B(x) = \widehat{\Er[y(0)|x]} Use main sample to regress with weights $(P(x)(1-P(X)))^{-1}$ y = \alpha_0 + \alpha_1 B(x) +  eta_0 (d-P(x)) +  eta_1 (d-P(x))(S(x) - \Er[S(x)]) + \epsilon $\hat{ eta} 0, \hat{ eta}_1 	o_p \argmin \Er[(s_0(x) - b_0 - b_1 (S(x)-E[S(x)]))^2]$ $\Lambda =  eta_1^2 Var(S(x)) = corr(s_0(x),S(X))^2 Var(s_0(x))$ library(kableExtra) colfn <- function(gml) { s <- genericML.summary(gml) c(s$blp[1], s$blp.se[1], s$blp[2], s$blp.se[2], s$Lambda[1]) } tbl <- cbind(colfn(gml.lasso), colfn(gml.rf), colfn(gml.nn)) colnames(tbl) <- c("Lasso","Regression forest","Neural network") rownames(tbl) <- c("ATE=b0","se","b1","se","Lambda") kable_styling(kable(tbl, caption="Machine learning proxies as BLP of CATE on Birthweight", format="html", digits=3), bootstrap_options = c("striped", "hover", "condensed", "responsive"), full_width=TRUE) Machine learning proxies as BLP of CATE on Birthweight Lasso Regression forest Neural network ATE=b0 -11.381 -1.751 6.185 se 31.414 32.285 32.309 b1 0.371 0.369 0.044 se 0.547 0.491 0.115 Lambda 601.155 683.726 372.192 Group average treatment effects [group-average-treatment-effects] ¶ Define $G_k = 1{\ell_{k-1} \leq S(x) \leq \ell_k}$ with 