("log_xp_percap","agecat","educ","tv","goat", "hh_toilet_own","motorbike","hh_cook_wood","pkh_ever") tmp <- data.frame() groupMeans <- function(var, gml, clusterid) { n.group <- ncol(gml$gate) gate <- matrix(NA, nrow=nrow(gml$gate), ncol=ncol(gml$gate)) gate.se <- gate dat <- data.frame(y=var) for (i in 1:ncol(gml$cate)) { S <- gml$cate[,i] cut <- quantile(S, probs=seq(0,1,length.out=(n.group+1))) cut[n.group+1] <- cut[n.group+1] + 1 for(k in 1:n.group) { dat[,sprintf("G.%d",k)] <- 1*(cut[k]<=S & S<cut[k+1]) } greg <- lm(as.formula(paste(c("y ~ -1", sprintf("G.%d",1:n.group)), collapse=" + ")), data=dat) gc <- grep("G", names(greg$coefficients)) gate[i,] <- greg$coefficients[gc] if (is.null(clusterid)) gate.se[i,] <- sqrt(diag(vcovHC(greg))[gc]) else gate.se[i,] <- sqrt(diag(vcovCL(greg,clusterid))[gc]) } return(list(mean=apply(gate, 2, function(x) median(x,na.rm=TRUE)), se = apply(gate.se, 2, function(x) median(x,na.rm=TRUE)))) } methods <- c("Lasso","Forest","Neural") gmls <- list(mw.lasso,mw.rf,mw.nn) for(v in vars) { for (m in 1:length(methods)) { gm <- groupMeans(df[,v], gmls[[m]], lid) tmp <- rbind(tmp, data.frame(group=1:length(gm$mean),variable=v, method=methods[m], mean=gm$mean, se=gm$se)) } } library(ggplot2) fig <- ggplot(data=tmp, aes(x=group, y=mean, colour=method)) + geom_line() + geom_line(aes(y=(mean+1.96*se), colour=method), linetype=2) + geom_line(aes(y=(mean-1.96*se), colour=method), linetype=2) + facet_wrap(~ variable,scales="free_y") + theme_minimal() print(fig) References ¶ Alatas, Vivi, Nur Cahyadi, Elisabeth Ekasari, Sarah Harmoun, Budi Hidayat, Edgar Janz, Jon Jellema, H Tuhiman, and M Wai-Poi. 2011. “Program Keluarga Harapan : Impact Evaluation of Indonesia’s Pilot Household Conditional Cash Transfer Program.” World Bank. http://documents.worldbank.org/curated/en/589171468266179965/Program-Keluarga-Harapan-impact-evaluation-of-Indonesias-Pilot-Household-Conditional-Cash-Transfer-Program . Chernozhukov, Victor, Mert Demirer, Esther Duflo, an